package com.example.ticktick;

import android.content.BroadcastReceiver;
import android.content.Context;
import android.content.Intent;

import com.example.ticktick.data.TaskDao;

public class BootReceiver extends BroadcastReceiver {
    @Override
    public void onReceive(Context context, Intent intent) {
        if (intent == null || intent.getAction() == null) return;
        if (!Intent.ACTION_BOOT_COMPLETED.equals(intent.getAction())
                && !Intent.ACTION_MY_PACKAGE_REPLACED.equals(intent.getAction())) {
            return;
        }
        TaskDao dao = new TaskDao(context);
        NotificationScheduler.rescheduleAll(context, dao.getAllTasks());
    }
}

package com.example.ticktick;

import android.Manifest;
import android.app.NotificationChannel;
import android.app.NotificationManager;
import android.content.BroadcastReceiver;
import android.content.Context;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.os.Build;

import androidx.core.app.NotificationCompat;
import androidx.core.app.NotificationManagerCompat;
import androidx.core.content.ContextCompat;

import com.example.ticktick.data.TaskDao;
import com.example.ticktick.model.Task;

public class DueTaskReceiver extends BroadcastReceiver {

    private static final String CHANNEL_ID = "due_events_channel";

    @Override
    public void onReceive(Context context, Intent intent) {
        int taskId = intent.getIntExtra(NotificationScheduler.EXTRA_TASK_ID, -1);
        if (taskId < 0) return;

        TaskDao dao = new TaskDao(context);
        Task task = dao.getTaskById(taskId);
        if (task == null || task.isCompleted()) return;

        ensureChannel(context);

        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU
                || ContextCompat.checkSelfPermission(context, Manifest.permission.POST_NOTIFICATIONS)
                == PackageManager.PERMISSION_GRANTED) {
            NotificationCompat.Builder builder = new NotificationCompat.Builder(context, CHANNEL_ID)
                    .setSmallIcon(R.drawable.ic_bell)
                    .setContentTitle(task.getTitle())
                    .setContentText(task.getDueDate() != null ? task.getDueDate() : context.getString(R.string.app_name))
                    .setPriority(NotificationCompat.PRIORITY_HIGH)
                    .setAutoCancel(true);
            try {
                NotificationManagerCompat.from(context).notify(taskId, builder.build());
            } catch (SecurityException ignored) {
                // Permission check failed at runtime
            }
        }

        String repeatType = task.getRepeatType();
        if (!Task.REPEAT_NONE.equals(repeatType)) {
            String nextDue = NotificationScheduler.computeNextDueDate(task.getDueDate(), repeatType);
            if (nextDue != null) {
                task.setDueDate(nextDue);
                dao.updateTask(task);
                NotificationScheduler.scheduleTaskReminder(context, task);
            }
        }
    }

    private void ensureChannel(Context context) {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.O) return;
        NotificationManager nm = context.getSystemService(NotificationManager.class);
        if (nm == null || nm.getNotificationChannel(CHANNEL_ID) != null) return;
        NotificationChannel channel = new NotificationChannel(
                CHANNEL_ID,
                context.getString(R.string.notification_channel_due_events),
                NotificationManager.IMPORTANCE_HIGH
        );
        channel.setDescription(context.getString(R.string.notification_channel_due_events_desc));
        nm.createNotificationChannel(channel);
    }
}

package com.example.ticktick;

import android.Manifest;
import android.app.AlertDialog;
import android.content.pm.PackageManager;
import android.content.res.ColorStateList;
import android.os.Build;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.Menu;
import android.view.MenuItem;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ImageButton;
import android.widget.LinearLayout;
import android.widget.NumberPicker;
import android.widget.PopupMenu;
import android.widget.TextView;
import android.widget.TimePicker;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.app.ActivityCompat;
import androidx.core.content.ContextCompat;
import androidx.drawerlayout.widget.DrawerLayout;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.ticktick.adapter.SidebarAdapter;
import com.example.ticktick.adapter.SubTaskAdapter;
import com.example.ticktick.adapter.TaskAdapter;
import com.example.ticktick.data.DataManager;
import com.example.ticktick.model.Task;
import com.google.android.material.bottomsheet.BottomSheetBehavior;
import com.google.android.material.floatingactionbutton.FloatingActionButton;
import com.google.android.material.switchmaterial.SwitchMaterial;

import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;
import java.util.Locale;

public class MainActivity extends AppCompatActivity {

    private DataManager dataManager;
    private String currentSection = "Next 7 Days";
    private String currentSortMode = "date"; // "date" | "name" | "list"
    private Task selectedTask = null;
    private String pendingExportSection = null;
    private static final int REQ_WRITE_STORAGE = 1001;

    private DrawerLayout drawerLayout;
    private RecyclerView rvSidebar, rvTasks, rvSubtasks;
    private TextView tvListTitle;
    private View cardTaskDetail;
    private View dimOverlay;
    private BottomSheetBehavior<View> bottomSheetBehavior;

    private TextView tvDetailTitle, tvDetailDate, tvDetailList, tvDetailDescription;
    private View detailListColor;
    private ImageButton btnDetailFlag, btnDetailMore;

    private TaskAdapter taskAdapter;
    private SidebarAdapter sidebarAdapter;
    private SubTaskAdapter subTaskAdapter;
    private ImageButton navTasks, navCalendar, navFocus, navProfile;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        dataManager = DataManager.getInstance(this);

        initViews();
        setupSidebar();
        setupTaskList();
        setupBottomNav();
        loadSection(currentSection);
    }

    private void initViews() {
        drawerLayout = findViewById(R.id.drawer_layout);

        ImageButton btnOpenDrawer = findViewById(R.id.btn_open_drawer);
        ImageButton btnSearch     = findViewById(R.id.btn_search);
        ImageButton btnSort       = findViewById(R.id.btn_sort);

        btnOpenDrawer.setOnClickListener(v -> drawerLayout.openDrawer(findViewById(R.id.sidebar)));
        btnSearch.setOnClickListener(v -> showSearchDialog());
        btnSort.setOnClickListener(v -> showSortMenu(btnSort));

        tvListTitle   = findViewById(R.id.tv_list_title);
        cardTaskDetail = findViewById(R.id.card_task_detail);
        dimOverlay     = findViewById(R.id.dim_overlay);

        // Set up BottomSheetBehavior
        bottomSheetBehavior = BottomSheetBehavior.from(cardTaskDetail);
        bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
        bottomSheetBehavior.addBottomSheetCallback(new BottomSheetBehavior.BottomSheetCallback() {
            @Override
            public void onStateChanged(@NonNull View bottomSheet, int newState) {
                if (newState == BottomSheetBehavior.STATE_HIDDEN) {
                    dimOverlay.setVisibility(View.GONE);
                    selectedTask = null;
                    taskAdapter.setSelectedTaskId(-1);
                }
            }
            @Override
            public void onSlide(@NonNull View bottomSheet, float slideOffset) {
                float alpha = Math.max(0f, slideOffset);
                dimOverlay.setVisibility(alpha > 0 ? View.VISIBLE : View.GONE);
                dimOverlay.setAlpha(alpha * 0.6f);
            }
        });
        dimOverlay.setOnClickListener(v ->
                bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN));

        FloatingActionButton fabAdd = findViewById(R.id.fab_add);
        LinearLayout btnAddTask     = findViewById(R.id.btn_add_task);
        fabAdd.setOnClickListener(v -> showAddTaskDialog());
        btnAddTask.setOnClickListener(v -> showAddTaskDialog());

        rvSidebar = findViewById(R.id.rv_sidebar);
        rvTasks   = findViewById(R.id.rv_tasks);

        // Detail panel
        tvDetailTitle       = findViewById(R.id.tv_detail_title);
        tvDetailDate        = findViewById(R.id.tv_detail_date);
        tvDetailList        = findViewById(R.id.tv_detail_list);
        tvDetailDescription = findViewById(R.id.tv_detail_description);
        detailListColor     = findViewById(R.id.detail_list_color);
        btnDetailFlag  = findViewById(R.id.btn_detail_flag);
        btnDetailMore  = findViewById(R.id.btn_detail_more);
        rvSubtasks     = findViewById(R.id.rv_subtasks);

        // Bottom nav
        navTasks    = findViewById(R.id.nav_tasks);
        navCalendar = findViewById(R.id.nav_calendar);
        navFocus    = findViewById(R.id.nav_focus);
        navProfile  = findViewById(R.id.nav_profile);
    }

    private void setupSidebar() {
        sidebarAdapter = new SidebarAdapter(dataManager.getSidebarItems(), item -> {
            if (item.getType() == com.example.ticktick.model.SidebarItem.TYPE_SECTION_HEADER) return;
            drawerLayout.closeDrawers();
            currentSection = item.getName();
            sidebarAdapter.setSelectedName(currentSection);
            loadSection(currentSection);
        });
        sidebarAdapter.setSelectedName(currentSection);
        rvSidebar.setLayoutManager(new LinearLayoutManager(this));
        rvSidebar.setAdapter(sidebarAdapter);
    }

    private void setupTaskList() {
        taskAdapter = new TaskAdapter(new TaskAdapter.OnTaskClickListener() {
            @Override
            public void onTaskClick(Task task) {
                selectedTask = task;
                taskAdapter.setSelectedTaskId(task.getId());
                showTaskDetail(task);
            }

            @Override
            public void onCheckboxClick(Task task) {
                dataManager.toggleTask(task.getId());
                // Re-bind the single changed item instead of reloading everything
                int pos = taskAdapter.getPositionForTaskId(task.getId());
                if (pos >= 0) taskAdapter.notifyItemChanged(pos);
                if (selectedTask != null && selectedTask.getId() == task.getId()) {
                    Task updated = dataManager.getTaskById(task.getId());
                    if (updated != null) showTaskDetail(updated);
                }
            }
        });
        rvTasks.setLayoutManager(new LinearLayoutManager(this));
        rvTasks.setItemAnimator(null); // disable default change animation for smoother checkbox taps
        rvTasks.setAdapter(taskAdapter);
    }

    private void setupBottomNav() {
        navTasks.setOnClickListener(v -> {
            currentSection = "Next 7 Days";
            sidebarAdapter.setSelectedName(currentSection);
            loadSection(currentSection);
            highlightBottomNav(navTasks);
        });
        navCalendar.setOnClickListener(v -> {
            currentSection = "Today";
            sidebarAdapter.setSelectedName(currentSection);
            loadSection(currentSection);
            highlightBottomNav(navCalendar);
        });
        navFocus.setOnClickListener(v -> {
            Toast.makeText(this, "Focus mode coming soon!", Toast.LENGTH_SHORT).show();
            highlightBottomNav(navFocus);
        });
        navProfile.setOnClickListener(v -> {
            Toast.makeText(this, "Profile coming soon!", Toast.LENGTH_SHORT).show();
            highlightBottomNav(navProfile);
        });
        highlightBottomNav(navTasks);
    }

    private void highlightBottomNav(ImageButton active) {
        int activeColor   = getColor(R.color.primary_blue);
        int inactiveColor = getColor(R.color.icon_inactive);
        navTasks.setColorFilter   (active == navTasks    ? activeColor : inactiveColor);
        navCalendar.setColorFilter(active == navCalendar ? activeColor : inactiveColor);
        navFocus.setColorFilter   (active == navFocus    ? activeColor : inactiveColor);
        navProfile.setColorFilter (active == navProfile  ? activeColor : inactiveColor);
    }

    private void loadSection(String section) {
        tvListTitle.setText(section);
        List<Object> items = new ArrayList<>();

        switch (section) {
            case "Today": {
                List<Task> tasks = sortedTasks(dataManager.getTodayTasks());
                if (!tasks.isEmpty()) { items.add("Today · " + tasks.size()); items.addAll(tasks); }
                break;
            }
            case "Next 7 Days": {
                List<Task> todayTasks    = sortedTasks(dataManager.getTodayTasks());
                List<Task> tomorrowTasks = sortedTasks(dataManager.getTomorrowTasks());
                List<Task> next7Tasks    = sortedTasks(dataManager.getNext7DaysTasks());
                if (!todayTasks.isEmpty()) {
                    items.add("Today · " + todayTasks.size()); items.addAll(todayTasks);
                }
                if (!tomorrowTasks.isEmpty()) {
                    items.add("Tomorrow · " + tomorrowTasks.size()); items.addAll(tomorrowTasks);
                }
                if (!next7Tasks.isEmpty()) {
                    items.add(DataManager.daysLaterString(2) + " · " + next7Tasks.size());
                    items.addAll(next7Tasks);
                }
                break;
            }
            case "Inbox": {
                List<Task> tasks = sortedTasks(dataManager.getAllTasks());
                if (!tasks.isEmpty()) { items.add("All Tasks · " + tasks.size()); items.addAll(tasks); }
                break;
            }
            case "Completed": {
                List<Task> tasks = sortedTasks(dataManager.getCompletedTasks());
                if (!tasks.isEmpty()) { items.add("Completed · " + tasks.size()); items.addAll(tasks); }
                break;
            }
            default: {
                List<Task> tasks = sortedTasks(dataManager.getTasksByList(section));
                if (!tasks.isEmpty()) { items.add(section + " · " + tasks.size()); items.addAll(tasks); }
                break;
            }
        }

        taskAdapter.setItems(items);
        selectedTask = null;
        taskAdapter.setSelectedTaskId(-1);
        bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
    }

    private void showTaskDetail(Task task) {
        bottomSheetBehavior.setState(BottomSheetBehavior.STATE_EXPANDED);
        tvDetailTitle.setText(task.getTitle());

        String due = task.getDueDate();
        if (due != null && !due.isEmpty()) {
            tvDetailDate.setVisibility(View.VISIBLE);
            tvDetailDate.setText(due);
        } else {
            tvDetailDate.setVisibility(View.GONE);
        }

        tvDetailList.setText(task.getListName() != null ? task.getListName() : "Inbox");

        String desc = task.getDescription();
        if (desc != null && !desc.isEmpty()) {
            tvDetailDescription.setVisibility(View.VISIBLE);
            tvDetailDescription.setText(desc);
        } else {
            tvDetailDescription.setVisibility(View.GONE);
        }

        detailListColor.setBackgroundTintList(
                ColorStateList.valueOf(getColor(getListColor(task.getListName()))));

        btnDetailFlag.setColorFilter(task.isHasFlag()
                ? getColor(R.color.priority_flag) : getColor(R.color.icon_inactive));

        btnDetailFlag.setOnClickListener(v -> {
            task.setHasFlag(!task.isHasFlag());
            dataManager.updateTask(task);
            btnDetailFlag.setColorFilter(task.isHasFlag()
                    ? getColor(R.color.priority_flag) : getColor(R.color.icon_inactive));
        });

        btnDetailMore.setOnClickListener(v -> showDetailMoreMenu(v, task));

        subTaskAdapter = new SubTaskAdapter(task.getSubTasks(), (subTask, pos) -> {
            subTask.setCompleted(!subTask.isCompleted());
            dataManager.updateTask(task);
            subTaskAdapter.notifyItemChanged(pos);
            int taskPos = taskAdapter.getPositionForTaskId(task.getId());
            if (taskPos >= 0) taskAdapter.notifyItemChanged(taskPos);
        });
        rvSubtasks.setLayoutManager(new LinearLayoutManager(this));
        rvSubtasks.setAdapter(subTaskAdapter);
    }

    private int getListColor(String listName) {
        if (listName == null) return R.color.text_secondary;
        switch (listName) {
            case "Work Tasks":   return R.color.tag_work;
            case "Study Goals":  return R.color.tag_study;
            case "Travel Plans": return R.color.tag_travel;
            case "Daily To-Dos": return R.color.tag_daily;
            case "Life Errands": return R.color.tag_life;
            default:             return R.color.primary_blue;
        }
    }

    private void showAddTaskDialog() {
        View dialogView = getLayoutInflater().inflate(R.layout.dialog_add_task, null);
        EditText etTitle       = dialogView.findViewById(R.id.et_task_title);
        EditText etDescription = dialogView.findViewById(R.id.et_task_description);
        TextView tvDate        = dialogView.findViewById(R.id.et_task_date);
        Button btnCancel       = dialogView.findViewById(R.id.btn_cancel);
        Button btnSave         = dialogView.findViewById(R.id.btn_save);
        final String[] selectedDate = {""};

        tvDate.setOnClickListener(v -> showDatePickerDialog(selectedDate[0], result -> {
            selectedDate[0] = result;
            tvDate.setText(result.isEmpty() ? "" : result);
            if (result.isEmpty()) tvDate.setHint(getString(R.string.due_date_hint));
        }));

        AlertDialog dialog = new AlertDialog.Builder(this)
                .setView(dialogView).setCancelable(true).create();
        if (dialog.getWindow() != null)
            dialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        btnCancel.setOnClickListener(v -> dialog.dismiss());
        btnSave.setOnClickListener(v -> {
            String title = etTitle.getText().toString().trim();
            if (TextUtils.isEmpty(title)) { etTitle.setError("Please enter a task name"); return; }

            String date = selectedDate[0];
            if (date.isEmpty() && (currentSection.equals("Today") || currentSection.equals("Next 7 Days"))) {
                date = DataManager.todayString();
            }
            String listName = isSmartSection(currentSection) ? "Work Tasks" : currentSection;
            Task newTask = new Task(0, title, false, date.isEmpty() ? null : date, listName);
            String desc = etDescription.getText().toString().trim();
            if (!desc.isEmpty()) newTask.setDescription(desc);
            dataManager.addTask(newTask);
            dialog.dismiss();
            loadSection(currentSection);
            refreshSidebar();
            rvTasks.scrollToPosition(0);
            Toast.makeText(this, "Task added!", Toast.LENGTH_SHORT).show();
        });
        dialog.show();
    }

    /** Parse "MMM d [yyyy] [HH:mm]" into milliseconds for comparison. Null / unparseable → Long.MAX_VALUE */
    private long parseDueDateToMillis(String dueDate) {
        if (dueDate == null || dueDate.isEmpty()) return Long.MAX_VALUE;
        String[] parts = dueDate.split(" ");
        try {
            int year = Calendar.getInstance().get(Calendar.YEAR);
            if (parts.length >= 3 && parts[2].matches("\\d{4}")) {
                year = Integer.parseInt(parts[2]);
            }
            SimpleDateFormat sdf = new SimpleDateFormat("MMM d yyyy", Locale.ENGLISH);
            java.util.Date d = sdf.parse(parts[0] + " " + parts[1] + " " + year);
            if (d == null) return Long.MAX_VALUE;
            long base = d.getTime();
            // add time component if present
            if (parts.length >= 4 && parts[3].contains(":")) {
                String[] hm = parts[3].split(":");
                base += (Integer.parseInt(hm[0]) * 3600L + Integer.parseInt(hm[1]) * 60L) * 1000L;
            } else if (parts.length == 3 && parts[2].contains(":")) {
                String[] hm = parts[2].split(":");
                base += (Integer.parseInt(hm[0]) * 3600L + Integer.parseInt(hm[1]) * 60L) * 1000L;
            }
            return base;
        } catch (Exception e) {
            return Long.MAX_VALUE;
        }
    }

    private List<Task> sortedTasks(List<Task> tasks) {
        List<Task> sorted = new ArrayList<>(tasks);
        switch (currentSortMode) {
            case "name":
                Collections.sort(sorted, (a, b) ->
                        a.getTitle().compareToIgnoreCase(b.getTitle()));
                break;
            case "list":
                Collections.sort(sorted, (a, b) -> {
                    String la = a.getListName() != null ? a.getListName() : "";
                    String lb = b.getListName() != null ? b.getListName() : "";
                    int cmp = la.compareToIgnoreCase(lb);
                    if (cmp != 0) return cmp;
                    // secondary: sort by date within same list
                    return Long.compare(parseDueDateToMillis(a.getDueDate()),
                                       parseDueDateToMillis(b.getDueDate()));
                });
                break;
            case "date":
            default:
                Collections.sort(sorted, (a, b) ->
                        Long.compare(parseDueDateToMillis(a.getDueDate()),
                                     parseDueDateToMillis(b.getDueDate())));
                break;
        }
        return sorted;
    }

    private boolean isSmartSection(String section) {
        switch (section) {
            case "Today": case "Next 7 Days": case "Inbox":
            case "Completed": case "This Week": case "Unscheduled":
                return true;
            default: return false;
        }
    }

    private void showDetailMoreMenu(View anchor, Task task) {
        PopupMenu popup = new PopupMenu(this, anchor);
        popup.getMenu().add(0, 1, 0, "Edit Task");
        popup.getMenu().add(0, 2, 1, "Delete Task");
        popup.setOnMenuItemClickListener(item -> {
            if (item.getItemId() == 1) showEditTaskDialog(task);
            else if (item.getItemId() == 2) showDeleteConfirm(task);
            return true;
        });
        popup.show();
    }

    private void showEditTaskDialog(Task task) {
        View dialogView = getLayoutInflater().inflate(R.layout.dialog_add_task, null);
        EditText etTitle       = dialogView.findViewById(R.id.et_task_title);
        EditText etDescription = dialogView.findViewById(R.id.et_task_description);
        TextView tvDate        = dialogView.findViewById(R.id.et_task_date);
        Button btnCancel       = dialogView.findViewById(R.id.btn_cancel);
        Button btnSave         = dialogView.findViewById(R.id.btn_save);

        etTitle.setText(task.getTitle());
        if (task.getDescription() != null) etDescription.setText(task.getDescription());
        String existing = task.getDueDate() != null ? task.getDueDate() : "";
        tvDate.setText(existing);
        final String[] selectedDate = {existing};

        tvDate.setOnClickListener(v -> showDatePickerDialog(selectedDate[0], result -> {
            selectedDate[0] = result;
            tvDate.setText(result.isEmpty() ? "" : result);
            if (result.isEmpty()) tvDate.setHint(getString(R.string.due_date_hint));
        }));

        AlertDialog dialog = new AlertDialog.Builder(this)
                .setView(dialogView).setCancelable(true).create();
        if (dialog.getWindow() != null)
            dialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        btnCancel.setOnClickListener(v -> dialog.dismiss());
        btnSave.setOnClickListener(v -> {
            String title = etTitle.getText().toString().trim();
            if (TextUtils.isEmpty(title)) { etTitle.setError("Please enter a task name"); return; }
            task.setTitle(title);
            String desc = etDescription.getText().toString().trim();
            task.setDescription(desc.isEmpty() ? null : desc);
            String date = selectedDate[0];
            task.setDueDate(date.isEmpty() ? null : date);
            dataManager.updateTask(task);
            loadSection(currentSection);
            Task updated = dataManager.getTaskById(task.getId());
            if (updated != null) showTaskDetail(updated);
            dialog.dismiss();
            Toast.makeText(this, "Task updated!", Toast.LENGTH_SHORT).show();
        });
        dialog.show();
    }

    private interface OnDatePickedListener { void onPicked(String dateString); }

    private void showDatePickerDialog(String currentValue, OnDatePickedListener callback) {
        View pickerView = getLayoutInflater().inflate(R.layout.dialog_date_picker, null);

        NumberPicker npDay    = pickerView.findViewById(R.id.np_day);
        NumberPicker npMonth  = pickerView.findViewById(R.id.np_month);
        NumberPicker npYear   = pickerView.findViewById(R.id.np_year);
        TimePicker timePicker = pickerView.findViewById(R.id.time_picker);
        SwitchMaterial switchTime = pickerView.findViewById(R.id.switch_time);

        final String[] monthNames = {"Jan","Feb","Mar","Apr","May","Jun",
                                     "Jul","Aug","Sep","Oct","Nov","Dec"};

        npMonth.setMinValue(0);
        npMonth.setMaxValue(11);
        npMonth.setDisplayedValues(monthNames);
        npMonth.setWrapSelectorWheel(true);

        Calendar cal = Calendar.getInstance();
        int currentYear = cal.get(Calendar.YEAR);
        npYear.setMinValue(currentYear);
        npYear.setMaxValue(currentYear + 10);
        npYear.setWrapSelectorWheel(false);

        npDay.setMinValue(1);
        npDay.setMaxValue(cal.getActualMaximum(Calendar.DAY_OF_MONTH));
        npDay.setWrapSelectorWheel(true);

        if (currentValue != null && !currentValue.isEmpty()) {
            try {
                SimpleDateFormat sdf = new SimpleDateFormat("MMM d", Locale.ENGLISH);
                String prefix = currentValue.length() >= 6
                        ? currentValue.substring(0, 6).trim() : currentValue;
                java.util.Date parsed = sdf.parse(prefix);
                if (parsed != null) {
                    Calendar tmp = Calendar.getInstance();
                    tmp.setTime(parsed);
                    npMonth.setValue(tmp.get(Calendar.MONTH));
                    npDay.setMaxValue(tmp.getActualMaximum(Calendar.DAY_OF_MONTH));
                    npDay.setValue(tmp.get(Calendar.DAY_OF_MONTH));
                }
                if (currentValue.contains(":")) {
                    String[] parts = currentValue.split(" ");
                    if (parts.length >= 3) {
                        String[] hm = parts[2].split(":");
                        timePicker.setHour(Integer.parseInt(hm[0]));
                        timePicker.setMinute(Integer.parseInt(hm[1]));
                        switchTime.setChecked(true);
                        timePicker.setVisibility(View.VISIBLE);
                    }
                }
            } catch (Exception ignored) {}
        } else {
            npMonth.setValue(cal.get(Calendar.MONTH));
            npDay.setValue(cal.get(Calendar.DAY_OF_MONTH));
            npYear.setValue(currentYear);
        }

        NumberPicker.OnValueChangeListener updateDays = (picker, oldVal, newVal) -> {
            Calendar tmp = Calendar.getInstance();
            tmp.set(Calendar.YEAR,  npYear.getValue());
            tmp.set(Calendar.MONTH, npMonth.getValue());
            int maxDay = tmp.getActualMaximum(Calendar.DAY_OF_MONTH);
            npDay.setMaxValue(maxDay);
            if (npDay.getValue() > maxDay) npDay.setValue(maxDay);
        };
        npMonth.setOnValueChangedListener(updateDays);
        npYear.setOnValueChangedListener(updateDays);

        switchTime.setOnCheckedChangeListener((btn, isChecked) ->
                timePicker.setVisibility(isChecked ? View.VISIBLE : View.GONE));

        AlertDialog pickerDialog = new AlertDialog.Builder(this)
                .setView(pickerView).setCancelable(true).create();
        if (pickerDialog.getWindow() != null)
            pickerDialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        pickerView.findViewById(R.id.btn_date_cancel).setOnClickListener(v -> pickerDialog.dismiss());
        pickerView.findViewById(R.id.btn_date_clear).setOnClickListener(v -> {
            callback.onPicked("");
            pickerDialog.dismiss();
        });
        pickerView.findViewById(R.id.btn_date_ok).setOnClickListener(v -> {
            String month = monthNames[npMonth.getValue()];
            int day  = npDay.getValue();
            int year = npYear.getValue();
            String dateStr = (year == currentYear)
                    ? month + " " + day
                    : month + " " + day + " " + year;
            if (switchTime.isChecked()) {
                dateStr += String.format(Locale.ENGLISH, " %02d:%02d",
                        timePicker.getHour(), timePicker.getMinute());
            }
            callback.onPicked(dateStr);
            pickerDialog.dismiss();
        });
        pickerDialog.show();
    }

    private void showDeleteConfirm(Task task) {
        new AlertDialog.Builder(this)
                .setTitle("Delete Task")
                .setMessage("Are you sure you want to delete \"" + task.getTitle() + "\"?")
                .setPositiveButton("Delete", (d, which) -> {
                    dataManager.deleteTask(task.getId());
                    selectedTask = null;
                    taskAdapter.setSelectedTaskId(-1);
                    bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
                    loadSection(currentSection);
                    Toast.makeText(this, "Task deleted", Toast.LENGTH_SHORT).show();
                })
                .setNegativeButton("Cancel", null)
                .show();
    }

    private void showSearchDialog() {
        View dialogView = getLayoutInflater().inflate(R.layout.dialog_add_task, null);
        EditText etTitle = dialogView.findViewById(R.id.et_task_title);
        etTitle.setHint(getString(R.string.search_hint));
        View dateField = dialogView.findViewById(R.id.et_task_date);
        dateField.setVisibility(View.GONE);
        Button btnCancel = dialogView.findViewById(R.id.btn_cancel);
        Button btnSave   = dialogView.findViewById(R.id.btn_save);
        btnSave.setText(R.string.search);

        AlertDialog dialog = new AlertDialog.Builder(this)
                .setView(dialogView).setCancelable(true).create();
        if (dialog.getWindow() != null)
            dialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        btnCancel.setOnClickListener(v -> dialog.dismiss());
        btnSave.setOnClickListener(v -> {
            String query = etTitle.getText().toString().trim().toLowerCase(Locale.ROOT);
            if (TextUtils.isEmpty(query)) { dialog.dismiss(); return; }
            List<Object> results = new ArrayList<>();
            results.add("Search: \"" + query + "\"");
            for (Task t : dataManager.getAllTasks()) {
                if (t.getTitle().toLowerCase(Locale.ROOT).contains(query)) results.add(t);
            }
            if (results.size() == 1) results.add("No tasks found");
            taskAdapter.setItems(results);
            tvListTitle.setText(R.string.search);
            selectedTask = null;
            taskAdapter.setSelectedTaskId(-1);
            bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
            dialog.dismiss();
        });
        dialog.show();
    }

    private void refreshSidebar() {
        sidebarAdapter.setItems(dataManager.getSidebarItems());
        sidebarAdapter.setSelectedName(currentSection);
    }

    private void showSortMenu(View anchor) {
        PopupMenu popup = new PopupMenu(this, anchor);
        // Sort options
        String dateLabel = "Sort by Date"  + ("date".equals(currentSortMode) ? " ✓" : "");
        String nameLabel = "Sort by Name"  + ("name".equals(currentSortMode) ? " ✓" : "");
        String listLabel = "Sort by List"  + ("list".equals(currentSortMode) ? " ✓" : "");
        popup.getMenu().add(0, 1, 0, dateLabel);
        popup.getMenu().add(0, 2, 1, nameLabel);
        popup.getMenu().add(0, 3, 2, listLabel);
        // Export options (divider via different group)
        popup.getMenu().add(1, 4, 3, getString(R.string.export_today));
        popup.getMenu().add(1, 5, 4, getString(R.string.export_7days));

        popup.setOnMenuItemClickListener(item -> {
            int id = item.getItemId();
            if (id == 1) {
                currentSortMode = "date";
                loadSection(currentSection);
                Toast.makeText(this, "Sorted by Date", Toast.LENGTH_SHORT).show();
            } else if (id == 2) {
                currentSortMode = "name";
                loadSection(currentSection);
                Toast.makeText(this, "Sorted by Name", Toast.LENGTH_SHORT).show();
            } else if (id == 3) {
                currentSortMode = "list";
                loadSection(currentSection);
                Toast.makeText(this, "Sorted by List", Toast.LENGTH_SHORT).show();
            } else if (id == 4) {
                triggerExport("Today");
            } else if (id == 5) {
                triggerExport("Next 7 Days");
            }
            return true;
        });
        popup.show();
    }

    private void triggerExport(String section) {
        // On API < 29 we need WRITE_EXTERNAL_STORAGE at runtime
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q &&
                ContextCompat.checkSelfPermission(this, Manifest.permission.WRITE_EXTERNAL_STORAGE)
                        != PackageManager.PERMISSION_GRANTED) {
            pendingExportSection = section;
            ActivityCompat.requestPermissions(this,
                    new String[]{Manifest.permission.WRITE_EXTERNAL_STORAGE},
                    REQ_WRITE_STORAGE);
            return;
        }
        doExport(section);
    }

    @Override
    public void onRequestPermissionsResult(int requestCode,
                                           @NonNull String[] permissions,
                                           @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        if (requestCode == REQ_WRITE_STORAGE) {
            if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                if (pendingExportSection != null) doExport(pendingExportSection);
            } else {
                Toast.makeText(this, "Storage permission required to export", Toast.LENGTH_SHORT).show();
            }
            pendingExportSection = null;
        }
    }

    private void doExport(String section) {
        List<Task> tasks = new ArrayList<>();
        if ("Today".equals(section)) {
            tasks.addAll(dataManager.getTodayTasks());
        } else {
            // Next 7 Days = today + tomorrow + next7
            tasks.addAll(dataManager.getTodayTasks());
            tasks.addAll(dataManager.getTomorrowTasks());
            tasks.addAll(dataManager.getNext7DaysTasks());
        }
        ExportHelper.export(this, section, tasks);
    }
}

package com.example.ticktick;

import android.Manifest;
import android.app.AlertDialog;
import android.content.pm.PackageManager;
import android.content.res.ColorStateList;
import android.os.Build;
import android.os.Bundle;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ImageButton;
import android.widget.LinearLayout;
import android.widget.NumberPicker;
import android.widget.PopupMenu;
import android.widget.TextView;
import android.widget.TimePicker;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.app.ActivityCompat;
import androidx.core.content.ContextCompat;
import androidx.drawerlayout.widget.DrawerLayout;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.ticktick.adapter.SidebarAdapter;
import com.example.ticktick.adapter.SubTaskAdapter;
import com.example.ticktick.adapter.TaskAdapter;
import com.example.ticktick.data.DataManager;
import com.example.ticktick.model.Task;
import com.google.android.material.bottomsheet.BottomSheetBehavior;
import com.google.android.material.floatingactionbutton.FloatingActionButton;
import com.google.android.material.switchmaterial.SwitchMaterial;

import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.Collections;
import java.util.List;
import java.util.Locale;

public class MainActivity extends AppCompatActivity {

    private DataManager dataManager;
    private String currentSection = "Next 7 Days";
    private String currentSortMode = "date"; // "date" | "name" | "list"
    private Task selectedTask = null;
    private String pendingExportSection = null;
    private static final int REQ_WRITE_STORAGE = 1001;
    private static final int REQ_POST_NOTIFICATIONS = 1002;

    private DrawerLayout drawerLayout;
    private RecyclerView rvSidebar, rvTasks, rvSubtasks;
    private TextView tvListTitle;
    private View cardTaskDetail;
    private View dimOverlay;
    private BottomSheetBehavior<View> bottomSheetBehavior;

    private TextView tvDetailTitle, tvDetailDate, tvDetailList, tvDetailDescription;
    private View detailListColor;
    private ImageButton btnDetailFlag, btnDetailMore;

    private TaskAdapter taskAdapter;
    private SidebarAdapter sidebarAdapter;
    private SubTaskAdapter subTaskAdapter;
    private ImageButton navTasks, navCalendar, navFocus, navProfile;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        dataManager = DataManager.getInstance(this);

        initViews();
        setupSidebar();
        setupTaskList();
        setupBottomNav();
        loadSection(currentSection);
        requestNotificationPermissionIfNeeded();
    }

    private void requestNotificationPermissionIfNeeded() {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU) return;
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS)
                == PackageManager.PERMISSION_GRANTED) return;
        ActivityCompat.requestPermissions(this,
                new String[]{Manifest.permission.POST_NOTIFICATIONS},
                REQ_POST_NOTIFICATIONS);
    }

    private void initViews() {
        drawerLayout = findViewById(R.id.drawer_layout);

        ImageButton btnOpenDrawer = findViewById(R.id.btn_open_drawer);
        ImageButton btnSearch     = findViewById(R.id.btn_search);
        ImageButton btnSort       = findViewById(R.id.btn_sort);

        btnOpenDrawer.setOnClickListener(v -> drawerLayout.openDrawer(findViewById(R.id.sidebar)));
        btnSearch.setOnClickListener(v -> showSearchDialog());
        btnSort.setOnClickListener(v -> showSortMenu(btnSort));

        tvListTitle   = findViewById(R.id.tv_list_title);
        cardTaskDetail = findViewById(R.id.card_task_detail);
        dimOverlay     = findViewById(R.id.dim_overlay);

        // Set up BottomSheetBehavior
        bottomSheetBehavior = BottomSheetBehavior.from(cardTaskDetail);
        bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
        bottomSheetBehavior.addBottomSheetCallback(new BottomSheetBehavior.BottomSheetCallback() {
            @Override
            public void onStateChanged(@NonNull View bottomSheet, int newState) {
                if (newState == BottomSheetBehavior.STATE_HIDDEN) {
                    dimOverlay.setVisibility(View.GONE);
                    selectedTask = null;
                    taskAdapter.setSelectedTaskId(-1);
                }
            }
            @Override
            public void onSlide(@NonNull View bottomSheet, float slideOffset) {
                float alpha = Math.max(0f, slideOffset);
                dimOverlay.setVisibility(alpha > 0 ? View.VISIBLE : View.GONE);
                dimOverlay.setAlpha(alpha * 0.6f);
            }
        });
        dimOverlay.setOnClickListener(v ->
                bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN));

        FloatingActionButton fabAdd = findViewById(R.id.fab_add);
        LinearLayout btnAddTask     = findViewById(R.id.btn_add_task);
        fabAdd.setOnClickListener(v -> showAddTaskDialog());
        btnAddTask.setOnClickListener(v -> showAddTaskDialog());

        rvSidebar = findViewById(R.id.rv_sidebar);
        rvTasks   = findViewById(R.id.rv_tasks);

        // Detail panel
        tvDetailTitle       = findViewById(R.id.tv_detail_title);
        tvDetailDate        = findViewById(R.id.tv_detail_date);
        tvDetailList        = findViewById(R.id.tv_detail_list);
        tvDetailDescription = findViewById(R.id.tv_detail_description);
        detailListColor     = findViewById(R.id.detail_list_color);
        btnDetailFlag  = findViewById(R.id.btn_detail_flag);
        btnDetailMore  = findViewById(R.id.btn_detail_more);
        rvSubtasks     = findViewById(R.id.rv_subtasks);

        // Bottom nav
        navTasks    = findViewById(R.id.nav_tasks);
        navCalendar = findViewById(R.id.nav_calendar);
        navFocus    = findViewById(R.id.nav_focus);
        navProfile  = findViewById(R.id.nav_profile);
    }

    private void setupSidebar() {
        sidebarAdapter = new SidebarAdapter(dataManager.getSidebarItems(), item -> {
            if (item.getType() == com.example.ticktick.model.SidebarItem.TYPE_SECTION_HEADER) return;
            drawerLayout.closeDrawers();
            currentSection = item.getName();
            sidebarAdapter.setSelectedName(currentSection);
            loadSection(currentSection);
        });
        sidebarAdapter.setSelectedName(currentSection);
        rvSidebar.setLayoutManager(new LinearLayoutManager(this));
        rvSidebar.setAdapter(sidebarAdapter);
    }

    private void setupTaskList() {
        taskAdapter = new TaskAdapter(new TaskAdapter.OnTaskClickListener() {
            @Override
            public void onTaskClick(Task task) {
                selectedTask = task;
                taskAdapter.setSelectedTaskId(task.getId());
                showTaskDetail(task);
            }

            @Override
            public void onCheckboxClick(Task task) {
                dataManager.toggleTask(task.getId());
                // Re-bind the single changed item instead of reloading everything
                int pos = taskAdapter.getPositionForTaskId(task.getId());
                if (pos >= 0) taskAdapter.notifyItemChanged(pos);
                if (selectedTask != null && selectedTask.getId() == task.getId()) {
                    Task updated = dataManager.getTaskById(task.getId());
                    if (updated != null) showTaskDetail(updated);
                }
            }
        });
        rvTasks.setLayoutManager(new LinearLayoutManager(this));
        rvTasks.setItemAnimator(null); // disable default change animation for smoother checkbox taps
        rvTasks.setAdapter(taskAdapter);
    }

    private void setupBottomNav() {
        navTasks.setOnClickListener(v -> {
            currentSection = "Next 7 Days";
            sidebarAdapter.setSelectedName(currentSection);
            loadSection(currentSection);
            highlightBottomNav(navTasks);
        });
        navCalendar.setOnClickListener(v -> {
            currentSection = "Today";
            sidebarAdapter.setSelectedName(currentSection);
            loadSection(currentSection);
            highlightBottomNav(navCalendar);
        });
        navFocus.setOnClickListener(v -> {
            Toast.makeText(this, "Focus mode coming soon!", Toast.LENGTH_SHORT).show();
            highlightBottomNav(navFocus);
        });
        navProfile.setOnClickListener(v -> {
            Toast.makeText(this, "Profile coming soon!", Toast.LENGTH_SHORT).show();
            highlightBottomNav(navProfile);
        });
        highlightBottomNav(navTasks);
    }

    private void highlightBottomNav(ImageButton active) {
        int activeColor   = getColor(R.color.primary_blue);
        int inactiveColor = getColor(R.color.icon_inactive);
        navTasks.setColorFilter   (active == navTasks    ? activeColor : inactiveColor);
        navCalendar.setColorFilter(active == navCalendar ? activeColor : inactiveColor);
        navFocus.setColorFilter   (active == navFocus    ? activeColor : inactiveColor);
        navProfile.setColorFilter (active == navProfile  ? activeColor : inactiveColor);
    }

    private void loadSection(String section) {
        tvListTitle.setText(section);
        List<Object> items = new ArrayList<>();

        switch (section) {
            case "Today": {
                List<Task> tasks = sortedTasks(dataManager.getTodayTasks());
                if (!tasks.isEmpty()) { items.add("Today · " + tasks.size()); items.addAll(tasks); }
                break;
            }
            case "Next 7 Days": {
                List<Task> todayTasks    = sortedTasks(dataManager.getTodayTasks());
                List<Task> tomorrowTasks = sortedTasks(dataManager.getTomorrowTasks());
                List<Task> next7Tasks    = sortedTasks(dataManager.getNext7DaysTasks());
                if (!todayTasks.isEmpty()) {
                    items.add("Today · " + todayTasks.size()); items.addAll(todayTasks);
                }
                if (!tomorrowTasks.isEmpty()) {
                    items.add("Tomorrow · " + tomorrowTasks.size()); items.addAll(tomorrowTasks);
                }
                if (!next7Tasks.isEmpty()) {
                    items.add(DataManager.daysLaterString(2) + " · " + next7Tasks.size());
                    items.addAll(next7Tasks);
                }
                break;
            }
            case "Inbox": {
                List<Task> tasks = sortedTasks(dataManager.getAllTasks());
                if (!tasks.isEmpty()) { items.add("All Tasks · " + tasks.size()); items.addAll(tasks); }
                break;
            }
            case "Completed": {
                List<Task> tasks = sortedTasks(dataManager.getCompletedTasks());
                if (!tasks.isEmpty()) { items.add("Completed · " + tasks.size()); items.addAll(tasks); }
                break;
            }
            default: {
                List<Task> tasks = sortedTasks(dataManager.getTasksByList(section));
                if (!tasks.isEmpty()) { items.add(section + " · " + tasks.size()); items.addAll(tasks); }
                break;
            }
        }

        taskAdapter.setItems(items);
        selectedTask = null;
        taskAdapter.setSelectedTaskId(-1);
        bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
    }

    private void showTaskDetail(Task task) {
        bottomSheetBehavior.setState(BottomSheetBehavior.STATE_EXPANDED);
        tvDetailTitle.setText(task.getTitle());

        String due = task.getDueDate();
        if (due != null && !due.isEmpty()) {
            tvDetailDate.setVisibility(View.VISIBLE);
            tvDetailDate.setText(due);
        } else {
            tvDetailDate.setVisibility(View.GONE);
        }

        tvDetailList.setText(task.getListName() != null ? task.getListName() : "Inbox");

        String desc = task.getDescription();
        if (desc != null && !desc.isEmpty()) {
            tvDetailDescription.setVisibility(View.VISIBLE);
            tvDetailDescription.setText(desc);
        } else {
            tvDetailDescription.setVisibility(View.GONE);
        }

        detailListColor.setBackgroundTintList(
                ColorStateList.valueOf(getColor(getListColor(task.getListName()))));

        btnDetailFlag.setColorFilter(task.isHasFlag()
                ? getColor(R.color.priority_flag) : getColor(R.color.icon_inactive));

        btnDetailFlag.setOnClickListener(v -> {
            task.setHasFlag(!task.isHasFlag());
            dataManager.updateTask(task);
            btnDetailFlag.setColorFilter(task.isHasFlag()
                    ? getColor(R.color.priority_flag) : getColor(R.color.icon_inactive));
        });

        btnDetailMore.setOnClickListener(v -> showDetailMoreMenu(v, task));

        subTaskAdapter = new SubTaskAdapter(task.getSubTasks(), (subTask, pos) -> {
            subTask.setCompleted(!subTask.isCompleted());
            dataManager.updateTask(task);
            subTaskAdapter.notifyItemChanged(pos);
            int taskPos = taskAdapter.getPositionForTaskId(task.getId());
            if (taskPos >= 0) taskAdapter.notifyItemChanged(taskPos);
        });
        rvSubtasks.setLayoutManager(new LinearLayoutManager(this));
        rvSubtasks.setAdapter(subTaskAdapter);
    }

    private int getListColor(String listName) {
        if (listName == null) return R.color.text_secondary;
        switch (listName) {
            case "Work Tasks":   return R.color.tag_work;
            case "Study Goals":  return R.color.tag_study;
            case "Travel Plans": return R.color.tag_travel;
            case "Daily To-Dos": return R.color.tag_daily;
            case "Life Errands": return R.color.tag_life;
            default:             return R.color.primary_blue;
        }
    }

    private void showAddTaskDialog() {
        View dialogView = getLayoutInflater().inflate(R.layout.dialog_add_task, null);
        EditText etTitle       = dialogView.findViewById(R.id.et_task_title);
        EditText etDescription = dialogView.findViewById(R.id.et_task_description);
        TextView tvDate        = dialogView.findViewById(R.id.et_task_date);
        TextView tvReminder    = dialogView.findViewById(R.id.tv_task_reminder);
        TextView tvRepeat      = dialogView.findViewById(R.id.tv_task_repeat);
        Button btnClear        = dialogView.findViewById(R.id.btn_clear_fields);
        Button btnCancel       = dialogView.findViewById(R.id.btn_cancel);
        Button btnSave         = dialogView.findViewById(R.id.btn_save);
        final String[] selectedDate = {""};
        final int[] selectedReminder = {-1};
        final String[] selectedRepeat = {Task.REPEAT_NONE};

        tvReminder.setText(reminderLabel(selectedReminder[0]));
        tvRepeat.setText(repeatLabel(selectedRepeat[0]));

        tvDate.setOnClickListener(v -> showDatePickerDialog(selectedDate[0], result -> {
            selectedDate[0] = result;
            tvDate.setText(result.isEmpty() ? "" : result);
            if (result.isEmpty()) tvDate.setHint(getString(R.string.due_date_hint));
        }));
        tvReminder.setOnClickListener(v -> showReminderMenu(tvReminder, selectedReminder));
        tvRepeat.setOnClickListener(v -> showRepeatMenu(tvRepeat, selectedRepeat));

        AlertDialog dialog = new AlertDialog.Builder(this)
                .setView(dialogView).setCancelable(true).create();
        if (dialog.getWindow() != null)
            dialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        btnClear.setOnClickListener(v -> {
            etTitle.setText("");
            etDescription.setText("");
            selectedDate[0] = "";
            tvDate.setText("");
            tvDate.setHint(getString(R.string.due_date_hint));
            selectedReminder[0] = -1;
            tvReminder.setText(reminderLabel(selectedReminder[0]));
            selectedRepeat[0] = Task.REPEAT_NONE;
            tvRepeat.setText(repeatLabel(selectedRepeat[0]));
        });
        btnCancel.setOnClickListener(v -> dialog.dismiss());
        btnSave.setOnClickListener(v -> {
            String title = etTitle.getText().toString().trim();
            if (TextUtils.isEmpty(title)) { etTitle.setError("Please enter a task name"); return; }

            String date = selectedDate[0];
            if (date.isEmpty() && (currentSection.equals("Today") || currentSection.equals("Next 7 Days"))) {
                date = DataManager.todayString();
            }
            if (selectedReminder[0] >= 0 && date.isEmpty()) {
                Toast.makeText(this, R.string.need_due_date_for_reminder, Toast.LENGTH_SHORT).show();
                return;
            }
            String listName = isSmartSection(currentSection) ? "Work Tasks" : currentSection;
            Task newTask = new Task(0, title, false, date.isEmpty() ? null : date, listName);
            String desc = etDescription.getText().toString().trim();
            if (!desc.isEmpty()) newTask.setDescription(desc);
            newTask.setReminderMinutes(selectedReminder[0]);
            newTask.setRepeatType(selectedRepeat[0]);
            newTask.setHasAlarm(selectedReminder[0] >= 0);
            dataManager.addTask(newTask);
            dialog.dismiss();
            loadSection(currentSection);
            refreshSidebar();
            rvTasks.scrollToPosition(0);
            Toast.makeText(this, "Task added!", Toast.LENGTH_SHORT).show();
        });
        dialog.show();
    }

    /** Parse "MMM d [yyyy] [HH:mm]" into milliseconds for comparison. Null / unparseable → Long.MAX_VALUE */
    private long parseDueDateToMillis(String dueDate) {
        return NotificationScheduler.parseDueDateToMillis(dueDate);
    }

    private List<Task> sortedTasks(List<Task> tasks) {
        List<Task> sorted = new ArrayList<>(tasks);
        switch (currentSortMode) {
            case "name":
                Collections.sort(sorted, (a, b) ->
                        a.getTitle().compareToIgnoreCase(b.getTitle()));
                break;
            case "list":
                Collections.sort(sorted, (a, b) -> {
                    String la = a.getListName() != null ? a.getListName() : "";
                    String lb = b.getListName() != null ? b.getListName() : "";
                    int cmp = la.compareToIgnoreCase(lb);
                    if (cmp != 0) return cmp;
                    // secondary: sort by date within same list
                    return Long.compare(parseDueDateToMillis(a.getDueDate()),
                                       parseDueDateToMillis(b.getDueDate()));
                });
                break;
            case "date":
            default:
                Collections.sort(sorted, (a, b) ->
                        Long.compare(parseDueDateToMillis(a.getDueDate()),
                                     parseDueDateToMillis(b.getDueDate())));
                break;
        }
        return sorted;
    }

    private boolean isSmartSection(String section) {
        switch (section) {
            case "Today": case "Next 7 Days": case "Inbox":
            case "Completed": case "This Week": case "Unscheduled":
                return true;
            default: return false;
        }
    }

    private void showDetailMoreMenu(View anchor, Task task) {
        PopupMenu popup = new PopupMenu(this, anchor);
        popup.getMenu().add(0, 1, 0, "Edit Task");
        popup.getMenu().add(0, 2, 1, "Delete Task");
        popup.setOnMenuItemClickListener(item -> {
            if (item.getItemId() == 1) showEditTaskDialog(task);
            else if (item.getItemId() == 2) showDeleteConfirm(task);
            return true;
        });
        popup.show();
    }

    private void showEditTaskDialog(Task task) {
        View dialogView = getLayoutInflater().inflate(R.layout.dialog_add_task, null);
        EditText etTitle       = dialogView.findViewById(R.id.et_task_title);
        EditText etDescription = dialogView.findViewById(R.id.et_task_description);
        TextView tvDate        = dialogView.findViewById(R.id.et_task_date);
        TextView tvReminder    = dialogView.findViewById(R.id.tv_task_reminder);
        TextView tvRepeat      = dialogView.findViewById(R.id.tv_task_repeat);
        Button btnClear        = dialogView.findViewById(R.id.btn_clear_fields);
        Button btnCancel       = dialogView.findViewById(R.id.btn_cancel);
        Button btnSave         = dialogView.findViewById(R.id.btn_save);

        etTitle.setText(task.getTitle());
        if (task.getDescription() != null) etDescription.setText(task.getDescription());
        String existing = task.getDueDate() != null ? task.getDueDate() : "";
        tvDate.setText(existing);
        final String[] selectedDate = {existing};
        final int[] selectedReminder = {task.getReminderMinutes() >= 0
                ? task.getReminderMinutes()
                : (task.isHasAlarm() ? 0 : -1)};
        final String[] selectedRepeat = {task.getRepeatType()};

        tvReminder.setText(reminderLabel(selectedReminder[0]));
        tvRepeat.setText(repeatLabel(selectedRepeat[0]));

        tvDate.setOnClickListener(v -> showDatePickerDialog(selectedDate[0], result -> {
            selectedDate[0] = result;
            tvDate.setText(result.isEmpty() ? "" : result);
            if (result.isEmpty()) tvDate.setHint(getString(R.string.due_date_hint));
        }));
        tvReminder.setOnClickListener(v -> showReminderMenu(tvReminder, selectedReminder));
        tvRepeat.setOnClickListener(v -> showRepeatMenu(tvRepeat, selectedRepeat));

        AlertDialog dialog = new AlertDialog.Builder(this)
                .setView(dialogView).setCancelable(true).create();
        if (dialog.getWindow() != null)
            dialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        btnClear.setOnClickListener(v -> {
            etDescription.setText("");
            selectedDate[0] = "";
            tvDate.setText("");
            tvDate.setHint(getString(R.string.due_date_hint));
            selectedReminder[0] = -1;
            tvReminder.setText(reminderLabel(selectedReminder[0]));
            selectedRepeat[0] = Task.REPEAT_NONE;
            tvRepeat.setText(repeatLabel(selectedRepeat[0]));
        });
        btnCancel.setOnClickListener(v -> dialog.dismiss());
        btnSave.setOnClickListener(v -> {
            String title = etTitle.getText().toString().trim();
            if (TextUtils.isEmpty(title)) { etTitle.setError("Please enter a task name"); return; }
            task.setTitle(title);
            String desc = etDescription.getText().toString().trim();
            task.setDescription(desc.isEmpty() ? null : desc);
            String date = selectedDate[0];
            if (selectedReminder[0] >= 0 && date.isEmpty()) {
                Toast.makeText(this, R.string.need_due_date_for_reminder, Toast.LENGTH_SHORT).show();
                return;
            }
            task.setDueDate(date.isEmpty() ? null : date);
            task.setReminderMinutes(selectedReminder[0]);
            task.setRepeatType(selectedRepeat[0]);
            task.setHasAlarm(selectedReminder[0] >= 0);
            dataManager.updateTask(task);
            loadSection(currentSection);
            Task updated = dataManager.getTaskById(task.getId());
            if (updated != null) showTaskDetail(updated);
            dialog.dismiss();
            Toast.makeText(this, "Task updated!", Toast.LENGTH_SHORT).show();
        });
        dialog.show();
    }

    private interface OnDatePickedListener { void onPicked(String dateString); }

    private void showDatePickerDialog(String currentValue, OnDatePickedListener callback) {
        View pickerView = getLayoutInflater().inflate(R.layout.dialog_date_picker, null);

        NumberPicker npDay    = pickerView.findViewById(R.id.np_day);
        NumberPicker npMonth  = pickerView.findViewById(R.id.np_month);
        NumberPicker npYear   = pickerView.findViewById(R.id.np_year);
        TimePicker timePicker = pickerView.findViewById(R.id.time_picker);
        SwitchMaterial switchTime = pickerView.findViewById(R.id.switch_time);

        final String[] monthNames = {"Jan","Feb","Mar","Apr","May","Jun",
                                     "Jul","Aug","Sep","Oct","Nov","Dec"};

        npMonth.setMinValue(0);
        npMonth.setMaxValue(11);
        npMonth.setDisplayedValues(monthNames);
        npMonth.setWrapSelectorWheel(true);

        Calendar cal = Calendar.getInstance();
        int currentYear = cal.get(Calendar.YEAR);
        npYear.setMinValue(currentYear);
        npYear.setMaxValue(currentYear + 10);
        npYear.setWrapSelectorWheel(false);

        npDay.setMinValue(1);
        npDay.setMaxValue(cal.getActualMaximum(Calendar.DAY_OF_MONTH));
        npDay.setWrapSelectorWheel(true);

        if (currentValue != null && !currentValue.isEmpty()) {
            try {
                SimpleDateFormat sdf = new SimpleDateFormat("MMM d", Locale.ENGLISH);
                String prefix = currentValue.length() >= 6
                        ? currentValue.substring(0, 6).trim() : currentValue;
                java.util.Date parsed = sdf.parse(prefix);
                if (parsed != null) {
                    Calendar tmp = Calendar.getInstance();
                    tmp.setTime(parsed);
                    npMonth.setValue(tmp.get(Calendar.MONTH));
                    npDay.setMaxValue(tmp.getActualMaximum(Calendar.DAY_OF_MONTH));
                    npDay.setValue(tmp.get(Calendar.DAY_OF_MONTH));
                }
                if (currentValue.contains(":")) {
                    String[] parts = currentValue.split(" ");
                    if (parts.length >= 3) {
                        String[] hm = parts[2].split(":");
                        timePicker.setHour(Integer.parseInt(hm[0]));
                        timePicker.setMinute(Integer.parseInt(hm[1]));
                        switchTime.setChecked(true);
                        timePicker.setVisibility(View.VISIBLE);
                    }
                }
            } catch (Exception ignored) {}
        } else {
            npMonth.setValue(cal.get(Calendar.MONTH));
            npDay.setValue(cal.get(Calendar.DAY_OF_MONTH));
            npYear.setValue(currentYear);
        }

        NumberPicker.OnValueChangeListener updateDays = (picker, oldVal, newVal) -> {
            Calendar tmp = Calendar.getInstance();
            tmp.set(Calendar.YEAR,  npYear.getValue());
            tmp.set(Calendar.MONTH, npMonth.getValue());
            int maxDay = tmp.getActualMaximum(Calendar.DAY_OF_MONTH);
            npDay.setMaxValue(maxDay);
            if (npDay.getValue() > maxDay) npDay.setValue(maxDay);
        };
        npMonth.setOnValueChangedListener(updateDays);
        npYear.setOnValueChangedListener(updateDays);

        switchTime.setOnCheckedChangeListener((btn, isChecked) ->
                timePicker.setVisibility(isChecked ? View.VISIBLE : View.GONE));

        AlertDialog pickerDialog = new AlertDialog.Builder(this)
                .setView(pickerView).setCancelable(true).create();
        if (pickerDialog.getWindow() != null)
            pickerDialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        pickerView.findViewById(R.id.btn_date_cancel).setOnClickListener(v -> pickerDialog.dismiss());
        pickerView.findViewById(R.id.btn_date_clear).setOnClickListener(v -> {
            callback.onPicked("");
            pickerDialog.dismiss();
        });
        pickerView.findViewById(R.id.btn_date_ok).setOnClickListener(v -> {
            String month = monthNames[npMonth.getValue()];
            int day  = npDay.getValue();
            int year = npYear.getValue();
            String dateStr = (year == currentYear)
                    ? month + " " + day
                    : month + " " + day + " " + year;
            if (switchTime.isChecked()) {
                dateStr += String.format(Locale.ENGLISH, " %02d:%02d",
                        timePicker.getHour(), timePicker.getMinute());
            }
            callback.onPicked(dateStr);
            pickerDialog.dismiss();
        });
        pickerDialog.show();
    }

    private void showDeleteConfirm(Task task) {
        new AlertDialog.Builder(this)
                .setTitle("Delete Task")
                .setMessage("Are you sure you want to delete \"" + task.getTitle() + "\"?")
                .setPositiveButton("Delete", (d, which) -> {
                    dataManager.deleteTask(task.getId());
                    selectedTask = null;
                    taskAdapter.setSelectedTaskId(-1);
                    bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
                    loadSection(currentSection);
                    Toast.makeText(this, "Task deleted", Toast.LENGTH_SHORT).show();
                })
                .setNegativeButton("Cancel", null)
                .show();
    }

    private void showSearchDialog() {
        View dialogView = getLayoutInflater().inflate(R.layout.dialog_add_task, null);
        EditText etTitle = dialogView.findViewById(R.id.et_task_title);
        etTitle.setHint(getString(R.string.search_hint));
        View dateField = dialogView.findViewById(R.id.et_task_date);
        View reminderField = dialogView.findViewById(R.id.tv_task_reminder);
        View repeatField = dialogView.findViewById(R.id.tv_task_repeat);
        View clearButton = dialogView.findViewById(R.id.btn_clear_fields);
        dateField.setVisibility(View.GONE);
        reminderField.setVisibility(View.GONE);
        repeatField.setVisibility(View.GONE);
        clearButton.setVisibility(View.GONE);
        Button btnCancel = dialogView.findViewById(R.id.btn_cancel);
        Button btnSave   = dialogView.findViewById(R.id.btn_save);
        btnSave.setText(R.string.search);

        AlertDialog dialog = new AlertDialog.Builder(this)
                .setView(dialogView).setCancelable(true).create();
        if (dialog.getWindow() != null)
            dialog.getWindow().setBackgroundDrawableResource(R.drawable.bg_card);

        btnCancel.setOnClickListener(v -> dialog.dismiss());
        btnSave.setOnClickListener(v -> {
            String query = etTitle.getText().toString().trim().toLowerCase(Locale.ROOT);
            if (TextUtils.isEmpty(query)) { dialog.dismiss(); return; }
            List<Object> results = new ArrayList<>();
            results.add("Search: \"" + query + "\"");
            for (Task t : dataManager.getAllTasks()) {
                if (t.getTitle().toLowerCase(Locale.ROOT).contains(query)) results.add(t);
            }
            if (results.size() == 1) results.add("No tasks found");
            taskAdapter.setItems(results);
            tvListTitle.setText(R.string.search);
            selectedTask = null;
            taskAdapter.setSelectedTaskId(-1);
            bottomSheetBehavior.setState(BottomSheetBehavior.STATE_HIDDEN);
            dialog.dismiss();
        });
        dialog.show();
    }

    private void refreshSidebar() {
        sidebarAdapter.setItems(dataManager.getSidebarItems());
        sidebarAdapter.setSelectedName(currentSection);
    }

    private void showSortMenu(View anchor) {
        PopupMenu popup = new PopupMenu(this, anchor);
        // Sort options
        String dateLabel = "Sort by Date"  + ("date".equals(currentSortMode) ? " ✓" : "");
        String nameLabel = "Sort by Name"  + ("name".equals(currentSortMode) ? " ✓" : "");
        String listLabel = "Sort by List"  + ("list".equals(currentSortMode) ? " ✓" : "");
        popup.getMenu().add(0, 1, 0, dateLabel);
        popup.getMenu().add(0, 2, 1, nameLabel);
        popup.getMenu().add(0, 3, 2, listLabel);
        // Export options (divider via different group)
        popup.getMenu().add(1, 4, 3, getString(R.string.export_today));
        popup.getMenu().add(1, 5, 4, getString(R.string.export_7days));

        popup.setOnMenuItemClickListener(item -> {
            int id = item.getItemId();
            if (id == 1) {
                currentSortMode = "date";
                loadSection(currentSection);
                Toast.makeText(this, "Sorted by Date", Toast.LENGTH_SHORT).show();
            } else if (id == 2) {
                currentSortMode = "name";
                loadSection(currentSection);
                Toast.makeText(this, "Sorted by Name", Toast.LENGTH_SHORT).show();
            } else if (id == 3) {
                currentSortMode = "list";
                loadSection(currentSection);
                Toast.makeText(this, "Sorted by List", Toast.LENGTH_SHORT).show();
            } else if (id == 4) {
                triggerExport("Today");
            } else if (id == 5) {
                triggerExport("Next 7 Days");
            }
            return true;
        });
        popup.show();
    }

    private void triggerExport(String section) {
        // On API < 29 we need WRITE_EXTERNAL_STORAGE at runtime
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q &&
                ContextCompat.checkSelfPermission(this, Manifest.permission.WRITE_EXTERNAL_STORAGE)
                        != PackageManager.PERMISSION_GRANTED) {
            pendingExportSection = section;
            ActivityCompat.requestPermissions(this,
                    new String[]{Manifest.permission.WRITE_EXTERNAL_STORAGE},
                    REQ_WRITE_STORAGE);
            return;
        }
        doExport(section);
    }

    @Override
    public void onRequestPermissionsResult(int requestCode,
                                           @NonNull String[] permissions,
                                           @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        if (requestCode == REQ_WRITE_STORAGE) {
            if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                if (pendingExportSection != null) doExport(pendingExportSection);
            } else {
                Toast.makeText(this, "Storage permission required to export", Toast.LENGTH_SHORT).show();
            }
            pendingExportSection = null;
        } else if (requestCode == REQ_POST_NOTIFICATIONS) {
            if (!(grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED)) {
                Toast.makeText(this, R.string.notification_permission_needed, Toast.LENGTH_SHORT).show();
            }
        }
    }

    private String reminderLabel(int reminderMinutes) {
        switch (reminderMinutes) {
            case 0: return getString(R.string.reminder_at_due);
            case 5: return getString(R.string.reminder_5m);
            case 15: return getString(R.string.reminder_15m);
            case 30: return getString(R.string.reminder_30m);
            case 60: return getString(R.string.reminder_1h);
            default: return getString(R.string.reminder_none);
        }
    }

    private String repeatLabel(String repeatType) {
        if (Task.REPEAT_DAILY.equals(repeatType)) return getString(R.string.repeat_daily);
        if (Task.REPEAT_WEEKLY.equals(repeatType)) return getString(R.string.repeat_weekly);
        if (Task.REPEAT_MONTHLY.equals(repeatType)) return getString(R.string.repeat_monthly);
        return getString(R.string.repeat_none);
    }

    private void showReminderMenu(View anchor, int[] selectedReminder) {
        PopupMenu popup = new PopupMenu(this, anchor);
        popup.getMenu().add(0, 1, 0, getString(R.string.reminder_none));
        popup.getMenu().add(0, 2, 1, getString(R.string.reminder_at_due));
        popup.getMenu().add(0, 3, 2, getString(R.string.reminder_5m));
        popup.getMenu().add(0, 4, 3, getString(R.string.reminder_15m));
        popup.getMenu().add(0, 5, 4, getString(R.string.reminder_30m));
        popup.getMenu().add(0, 6, 5, getString(R.string.reminder_1h));
        popup.setOnMenuItemClickListener(item -> {
            switch (item.getItemId()) {
                case 2: selectedReminder[0] = 0; break;
                case 3: selectedReminder[0] = 5; break;
                case 4: selectedReminder[0] = 15; break;
                case 5: selectedReminder[0] = 30; break;
                case 6: selectedReminder[0] = 60; break;
                default: selectedReminder[0] = -1; break;
            }
            ((TextView) anchor).setText(reminderLabel(selectedReminder[0]));
            return true;
        });
        popup.show();
    }

    private void showRepeatMenu(View anchor, String[] selectedRepeat) {
        PopupMenu popup = new PopupMenu(this, anchor);
        popup.getMenu().add(0, 1, 0, getString(R.string.repeat_none));
        popup.getMenu().add(0, 2, 1, getString(R.string.repeat_daily));
        popup.getMenu().add(0, 3, 2, getString(R.string.repeat_weekly));
        popup.getMenu().add(0, 4, 3, getString(R.string.repeat_monthly));
        popup.setOnMenuItemClickListener(item -> {
            switch (item.getItemId()) {
                case 2: selectedRepeat[0] = Task.REPEAT_DAILY; break;
                case 3: selectedRepeat[0] = Task.REPEAT_WEEKLY; break;
                case 4: selectedRepeat[0] = Task.REPEAT_MONTHLY; break;
                default: selectedRepeat[0] = Task.REPEAT_NONE; break;
            }
            ((TextView) anchor).setText(repeatLabel(selectedRepeat[0]));
            return true;
        });
        popup.show();
    }

    private void doExport(String section) {
        List<Task> tasks = new ArrayList<>();
        if ("Today".equals(section)) {
            tasks.addAll(dataManager.getTodayTasks());
        } else {
            // Next 7 Days = today + tomorrow + next7
            tasks.addAll(dataManager.getTodayTasks());
            tasks.addAll(dataManager.getTomorrowTasks());
            tasks.addAll(dataManager.getNext7DaysTasks());
        }
        ExportHelper.export(this, section, tasks);
    }
}

package com.example.ticktick;

import android.app.AlarmManager;
import android.app.PendingIntent;
import android.content.Context;
import android.content.Intent;

import com.example.ticktick.model.Task;

import java.text.SimpleDateFormat;
import java.util.Calendar;
import java.util.List;
import java.util.Locale;

public final class NotificationScheduler {

    public static final String EXTRA_TASK_ID = "extra_task_id";
    private static final String MONTH_DAY_PATTERN = "MMM d yyyy";

    private NotificationScheduler() {}

    public static void rescheduleAll(Context context, List<Task> tasks) {
        if (tasks == null) return;
        for (Task task : tasks) {
            scheduleTaskReminder(context, task);
        }
    }

    public static void scheduleTaskReminder(Context context, Task task) {
        if (context == null || task == null) return;
        cancelTaskReminder(context, task.getId());

        long triggerAtMillis = computeReminderTrigger(task, System.currentTimeMillis());
        if (triggerAtMillis == Long.MAX_VALUE) return;

        AlarmManager alarmManager = (AlarmManager) context.getSystemService(Context.ALARM_SERVICE);
        if (alarmManager == null) return;

        PendingIntent pi = buildPendingIntent(context, task.getId());
        alarmManager.setAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerAtMillis, pi);
    }

    public static void cancelTaskReminder(Context context, int taskId) {
        if (context == null) return;
        AlarmManager alarmManager = (AlarmManager) context.getSystemService(Context.ALARM_SERVICE);
        if (alarmManager == null) return;
        alarmManager.cancel(buildPendingIntent(context, taskId));
    }

    public static long computeReminderTrigger(Task task, long now) {
        if (task == null || task.isCompleted() || task.getDueDate() == null || task.getDueDate().isEmpty()) {
            return Long.MAX_VALUE;
        }

        int reminderMinutes = task.getReminderMinutes();
        if (reminderMinutes < 0 && task.isHasAlarm()) reminderMinutes = 0;
        if (reminderMinutes < 0) return Long.MAX_VALUE;

        long dueMillis = parseDueDateToMillis(task.getDueDate());
        if (dueMillis == Long.MAX_VALUE) return Long.MAX_VALUE;

        long triggerAt = dueMillis - reminderMinutes * 60_000L;
        String repeatType = task.getRepeatType();
        while (!Task.REPEAT_NONE.equals(repeatType) && triggerAt <= now) {
            String nextDueDate = computeNextDueDate(task.getDueDate(), repeatType);
            if (nextDueDate == null) return Long.MAX_VALUE;
            task.setDueDate(nextDueDate);
            dueMillis = parseDueDateToMillis(nextDueDate);
            if (dueMillis == Long.MAX_VALUE) return Long.MAX_VALUE;
            triggerAt = dueMillis - reminderMinutes * 60_000L;
        }

        if (Task.REPEAT_NONE.equals(repeatType) && triggerAt <= now) return Long.MAX_VALUE;
        return triggerAt;
    }

    public static String computeNextDueDate(String dueDate, String repeatType) {
        if (dueDate == null || dueDate.isEmpty()) return null;
        ParsedDate parsedDate = parseDueDate(dueDate);
        if (parsedDate == null) return null;

        switch (repeatType) {
            case Task.REPEAT_DAILY:
                parsedDate.calendar.add(Calendar.DAY_OF_YEAR, 1);
                break;
            case Task.REPEAT_WEEKLY:
                parsedDate.calendar.add(Calendar.DAY_OF_YEAR, 7);
                break;
            case Task.REPEAT_MONTHLY:
                parsedDate.calendar.add(Calendar.MONTH, 1);
                break;
            default:
                return dueDate;
        }

        String base = new SimpleDateFormat(MONTH_DAY_PATTERN, Locale.ENGLISH)
                .format(parsedDate.calendar.getTime());
        if (!parsedDate.hasExplicitYear) {
            int currentYear = Calendar.getInstance().get(Calendar.YEAR);
            if (parsedDate.calendar.get(Calendar.YEAR) == currentYear) {
                base = new SimpleDateFormat("MMM d", Locale.ENGLISH).format(parsedDate.calendar.getTime());
            }
        }
        if (parsedDate.hasTime) {
            base += String.format(Locale.ENGLISH, " %02d:%02d",
                    parsedDate.calendar.get(Calendar.HOUR_OF_DAY),
                    parsedDate.calendar.get(Calendar.MINUTE));
        }
        return base;
    }

    public static long parseDueDateToMillis(String dueDate) {
        ParsedDate parsedDate = parseDueDate(dueDate);
        if (parsedDate == null) return Long.MAX_VALUE;
        return parsedDate.calendar.getTimeInMillis();
    }

    private static ParsedDate parseDueDate(String dueDate) {
        if (dueDate == null || dueDate.isEmpty()) return null;
        String[] parts = dueDate.trim().split("\\s+");
        if (parts.length < 2) return null;

        try {
            int month = monthToInt(parts[0]);
            int day = Integer.parseInt(parts[1]);
            int index = 2;

            Calendar cal = Calendar.getInstance();
            int year = cal.get(Calendar.YEAR);
            boolean hasExplicitYear = false;
            if (parts.length > index && parts[index].matches("\\d{4}")) {
                year = Integer.parseInt(parts[index]);
                hasExplicitYear = true;
                index++;
            }

            int hour = 9;
            int minute = 0;
            boolean hasTime = false;
            if (parts.length > index && parts[index].contains(":")) {
                String[] hm = parts[index].split(":");
                hour = Integer.parseInt(hm[0]);
                minute = Integer.parseInt(hm[1]);
                hasTime = true;
            }

            cal.set(Calendar.YEAR, year);
            cal.set(Calendar.MONTH, month);
            cal.set(Calendar.DAY_OF_MONTH, day);
            cal.set(Calendar.HOUR_OF_DAY, hour);
            cal.set(Calendar.MINUTE, minute);
            cal.set(Calendar.SECOND, 0);
            cal.set(Calendar.MILLISECOND, 0);

            ParsedDate parsed = new ParsedDate();
            parsed.calendar = cal;
            parsed.hasTime = hasTime;
            parsed.hasExplicitYear = hasExplicitYear;
            return parsed;
        } catch (Exception ignored) {
            return null;
        }
    }

    private static int monthToInt(String month) {
        switch (month) {
            case "Jan": return Calendar.JANUARY;
            case "Feb": return Calendar.FEBRUARY;
            case "Mar": return Calendar.MARCH;
            case "Apr": return Calendar.APRIL;
            case "May": return Calendar.MAY;
            case "Jun": return Calendar.JUNE;
            case "Jul": return Calendar.JULY;
            case "Aug": return Calendar.AUGUST;
            case "Sep": return Calendar.SEPTEMBER;
            case "Oct": return Calendar.OCTOBER;
            case "Nov": return Calendar.NOVEMBER;
            case "Dec": return Calendar.DECEMBER;
            default: throw new IllegalArgumentException("Unknown month: " + month);
        }
    }

    private static PendingIntent buildPendingIntent(Context context, int taskId) {
        Intent intent = new Intent(context, com.example.ticktick.DueTaskReceiver.class);
        intent.putExtra(EXTRA_TASK_ID, taskId);
        return PendingIntent.getBroadcast(
                context,
                taskId,
                intent,
                PendingIntent.FLAG_UPDATE_CURRENT | PendingIntent.FLAG_IMMUTABLE
        );
    }

    private static class ParsedDate {
        Calendar calendar;
        boolean hasTime;
        boolean hasExplicitYear;
    }
}

package com.example.ticktick.data;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;

import com.example.ticktick.model.Task;

import java.util.ArrayList;
import java.util.List;

public class TaskDao {
    private final TaskDbHelper dbHelper;

    public TaskDao(Context context) {
        dbHelper = new TaskDbHelper(context.getApplicationContext());
    }

    // ── Insert ─────────────────────────────────────────────────────────────
    public Task insertTask(Task task) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        long newId = db.insert(TaskDbHelper.TABLE_TASKS, null, taskToValues(task));
        task.setId((int) newId);
        for (Task.SubTask sub : task.getSubTasks()) {
            insertSubTask((int) newId, sub, db);
        }
        return task;
    }

    // ── Update ─────────────────────────────────────────────────────────────
    public void updateTask(Task task) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        db.update(TaskDbHelper.TABLE_TASKS,
                taskToValues(task),
                TaskDbHelper.COL_ID + " = ?",
                new String[]{String.valueOf(task.getId())});

        db.delete(TaskDbHelper.TABLE_SUBTASKS,
                TaskDbHelper.COL_SUB_TASK_ID + " = ?",
                new String[]{String.valueOf(task.getId())});
        for (Task.SubTask sub : task.getSubTasks()) {
            insertSubTask(task.getId(), sub, db);
        }
    }

    public void toggleTask(int id) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        db.execSQL(
                "UPDATE " + TaskDbHelper.TABLE_TASKS
                + " SET " + TaskDbHelper.COL_COMPLETED
                + " = 1 - " + TaskDbHelper.COL_COMPLETED
                + " WHERE " + TaskDbHelper.COL_ID + " = ?",
                new Object[]{id});
    }

    // ── Delete ─────────────────────────────────────────────────────────────
    public void deleteTask(int id) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        // Delete sub-tasks explicitly as a safety net
        db.delete(TaskDbHelper.TABLE_SUBTASKS,
                TaskDbHelper.COL_SUB_TASK_ID + " = ?",
                new String[]{String.valueOf(id)});
        db.delete(TaskDbHelper.TABLE_TASKS,
                TaskDbHelper.COL_ID + " = ?",
                new String[]{String.valueOf(id)});
    }

    // ── Read ───────────────────────────────────────────────────────────────
    public List<Task> getAllTasks() {
        SQLiteDatabase db = dbHelper.getReadableDatabase();
        List<Task> tasks = new ArrayList<>();

        Cursor c = db.query(TaskDbHelper.TABLE_TASKS,
                null, null, null, null, null,
                TaskDbHelper.COL_ID + " ASC");
        while (c.moveToNext()) tasks.add(cursorToTask(c));
        c.close();

        for (Task t : tasks) loadSubTasks(t, db);
        return tasks;
    }

    public Task getTaskById(int id) {
        SQLiteDatabase db = dbHelper.getReadableDatabase();
        Cursor c = db.query(TaskDbHelper.TABLE_TASKS,
                null,
                TaskDbHelper.COL_ID + " = ?",
                new String[]{String.valueOf(id)},
                null, null, null);
        Task task = null;
        if (c.moveToFirst()) {
            task = cursorToTask(c);
            loadSubTasks(task, db);
        }
        c.close();
        return task;
    }

    public boolean isEmpty() {
        SQLiteDatabase db = dbHelper.getReadableDatabase();
        Cursor c = db.rawQuery("SELECT COUNT(*) FROM " + TaskDbHelper.TABLE_TASKS, null);
        int count = 0;
        if (c.moveToFirst()) count = c.getInt(0);
        c.close();
        return count == 0;
    }

    // ── Helpers ────────────────────────────────────────────────────────────
    private ContentValues taskToValues(Task t) {
        ContentValues cv = new ContentValues();
        cv.put(TaskDbHelper.COL_TITLE,     t.getTitle());
        cv.put(TaskDbHelper.COL_COMPLETED, t.isCompleted()  ? 1 : 0);
        cv.put(TaskDbHelper.COL_DUE_DATE,  t.getDueDate());
        cv.put(TaskDbHelper.COL_LIST_NAME, t.getListName());
        cv.put(TaskDbHelper.COL_HAS_ALARM, t.isHasAlarm()   ? 1 : 0);
        cv.put(TaskDbHelper.COL_HAS_FLAG,  t.isHasFlag()    ? 1 : 0);
        return cv;
    }

    private void insertSubTask(int taskId, Task.SubTask sub, SQLiteDatabase db) {
        ContentValues cv = new ContentValues();
        cv.put(TaskDbHelper.COL_SUB_TASK_ID,   taskId);
        cv.put(TaskDbHelper.COL_SUB_TITLE,     sub.getTitle());
        cv.put(TaskDbHelper.COL_SUB_COMPLETED, sub.isCompleted() ? 1 : 0);
        db.insert(TaskDbHelper.TABLE_SUBTASKS, null, cv);
    }

    private Task cursorToTask(Cursor c) {
        int     id        = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_ID));
        String  title     = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_TITLE));
        boolean completed = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_COMPLETED)) == 1;
        String  dueDate   = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_DUE_DATE));
        String  listName  = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_LIST_NAME));
        boolean hasAlarm  = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_HAS_ALARM)) == 1;
        boolean hasFlag   = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_HAS_FLAG))  == 1;

        Task task = new Task(id, title, completed, dueDate, listName);
        task.setHasAlarm(hasAlarm);
        task.setHasFlag(hasFlag);
        return task;
    }

    private void loadSubTasks(Task task, SQLiteDatabase db) {
        Cursor c = db.query(TaskDbHelper.TABLE_SUBTASKS,
                null,
                TaskDbHelper.COL_SUB_TASK_ID + " = ?",
                new String[]{String.valueOf(task.getId())},
                null, null, null);
        while (c.moveToNext()) {
            String  title     = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_SUB_TITLE));
            boolean completed = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_SUB_COMPLETED)) == 1;
            Task.SubTask sub = new Task.SubTask(title);
            sub.setCompleted(completed);
            task.getSubTasks().add(sub);
        }
        c.close();
    }
}

package com.example.ticktick.data;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;

import com.example.ticktick.model.Task;

import java.util.ArrayList;
import java.util.List;

public class TaskDao {
    private final TaskDbHelper dbHelper;

    public TaskDao(Context context) {
        dbHelper = new TaskDbHelper(context.getApplicationContext());
    }

    // ── Insert ─────────────────────────────────────────────────────────────
    public Task insertTask(Task task) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        long newId = db.insert(TaskDbHelper.TABLE_TASKS, null, taskToValues(task));
        task.setId((int) newId);
        for (Task.SubTask sub : task.getSubTasks()) {
            insertSubTask((int) newId, sub, db);
        }
        return task;
    }

    // ── Update ─────────────────────────────────────────────────────────────
    public void updateTask(Task task) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        db.update(TaskDbHelper.TABLE_TASKS,
                taskToValues(task),
                TaskDbHelper.COL_ID + " = ?",
                new String[]{String.valueOf(task.getId())});

        db.delete(TaskDbHelper.TABLE_SUBTASKS,
                TaskDbHelper.COL_SUB_TASK_ID + " = ?",
                new String[]{String.valueOf(task.getId())});
        for (Task.SubTask sub : task.getSubTasks()) {
            insertSubTask(task.getId(), sub, db);
        }
    }

    public void toggleTask(int id) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        db.execSQL(
                "UPDATE " + TaskDbHelper.TABLE_TASKS
                + " SET " + TaskDbHelper.COL_COMPLETED
                + " = 1 - " + TaskDbHelper.COL_COMPLETED
                + " WHERE " + TaskDbHelper.COL_ID + " = ?",
                new Object[]{id});
    }

    // ── Delete ─────────────────────────────────────────────────────────────
    public void deleteTask(int id) {
        SQLiteDatabase db = dbHelper.getWritableDatabase();
        // Delete sub-tasks explicitly as a safety net
        db.delete(TaskDbHelper.TABLE_SUBTASKS,
                TaskDbHelper.COL_SUB_TASK_ID + " = ?",
                new String[]{String.valueOf(id)});
        db.delete(TaskDbHelper.TABLE_TASKS,
                TaskDbHelper.COL_ID + " = ?",
                new String[]{String.valueOf(id)});
    }

    // ── Read ───────────────────────────────────────────────────────────────
    public List<Task> getAllTasks() {
        SQLiteDatabase db = dbHelper.getReadableDatabase();
        List<Task> tasks = new ArrayList<>();

        Cursor c = db.query(TaskDbHelper.TABLE_TASKS,
                null, null, null, null, null,
                TaskDbHelper.COL_ID + " ASC");
        while (c.moveToNext()) tasks.add(cursorToTask(c));
        c.close();

        for (Task t : tasks) loadSubTasks(t, db);
        return tasks;
    }

    public Task getTaskById(int id) {
        SQLiteDatabase db = dbHelper.getReadableDatabase();
        Cursor c = db.query(TaskDbHelper.TABLE_TASKS,
                null,
                TaskDbHelper.COL_ID + " = ?",
                new String[]{String.valueOf(id)},
                null, null, null);
        Task task = null;
        if (c.moveToFirst()) {
            task = cursorToTask(c);
            loadSubTasks(task, db);
        }
        c.close();
        return task;
    }

    public boolean isEmpty() {
        SQLiteDatabase db = dbHelper.getReadableDatabase();
        Cursor c = db.rawQuery("SELECT COUNT(*) FROM " + TaskDbHelper.TABLE_TASKS, null);
        int count = 0;
        if (c.moveToFirst()) count = c.getInt(0);
        c.close();
        return count == 0;
    }

    // ── Helpers ────────────────────────────────────────────────────────────
    private ContentValues taskToValues(Task t) {
        ContentValues cv = new ContentValues();
        cv.put(TaskDbHelper.COL_TITLE,     t.getTitle());
        cv.put(TaskDbHelper.COL_COMPLETED, t.isCompleted()  ? 1 : 0);
        cv.put(TaskDbHelper.COL_DUE_DATE,  t.getDueDate());
        cv.put(TaskDbHelper.COL_LIST_NAME, t.getListName());
        cv.put(TaskDbHelper.COL_HAS_ALARM, t.isHasAlarm()   ? 1 : 0);
        cv.put(TaskDbHelper.COL_HAS_FLAG,  t.isHasFlag()    ? 1 : 0);
        cv.put(TaskDbHelper.COL_DESCRIPTION, t.getDescription());
        cv.put(TaskDbHelper.COL_REMINDER_MINUTES, t.getReminderMinutes());
        cv.put(TaskDbHelper.COL_REPEAT_TYPE, t.getRepeatType());
        return cv;
    }

    private void insertSubTask(int taskId, Task.SubTask sub, SQLiteDatabase db) {
        ContentValues cv = new ContentValues();
        cv.put(TaskDbHelper.COL_SUB_TASK_ID,   taskId);
        cv.put(TaskDbHelper.COL_SUB_TITLE,     sub.getTitle());
        cv.put(TaskDbHelper.COL_SUB_COMPLETED, sub.isCompleted() ? 1 : 0);
        db.insert(TaskDbHelper.TABLE_SUBTASKS, null, cv);
    }

    private Task cursorToTask(Cursor c) {
        int     id        = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_ID));
        String  title     = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_TITLE));
        boolean completed = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_COMPLETED)) == 1;
        String  dueDate   = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_DUE_DATE));
        String  listName  = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_LIST_NAME));
        boolean hasAlarm  = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_HAS_ALARM)) == 1;
        boolean hasFlag   = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_HAS_FLAG))  == 1;
        String description = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_DESCRIPTION));
        int reminderMinutes = c.getInt(c.getColumnIndexOrThrow(TaskDbHelper.COL_REMINDER_MINUTES));
        String repeatType = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_REPEAT_TYPE));

        Task task = new Task(id, title, completed, dueDate, listName);
        task.setHasAlarm(hasAlarm);
        task.setHasFlag(hasFlag);
        task.setDescription(description);
        task.setReminderMinutes(reminderMinutes);
        task.setRepeatType(repeatType);
        return task;
    }

    private void loadSubTasks(Task task, SQLiteDatabase db) {
        Cursor c = db.query(TaskDbHelper.TABLE_SUBTASKS,
                null,
                TaskDbHelper.COL_SUB_TASK_ID + " = ?",
                new String[]{String.valueOf(task.getId())},
                null, null, null);
        while (c.moveToNext()) {
            String  title     = c.getString(c.getColumnIndexOrThrow(TaskDbHelper.COL_SUB_TITLE));
            boolean completed = c.getInt   (c.getColumnIndexOrThrow(TaskDbHelper.COL_SUB_COMPLETED)) == 1;
            Task.SubTask sub = new Task.SubTask(title);
            sub.setCompleted(completed);
            task.getSubTasks().add(sub);
        }
        c.close();
    }
}

package com.example.ticktick.data;

import android.content.Context;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;


public class TaskDbHelper extends SQLiteOpenHelper {
    static final String DATABASE_NAME    = "ticktick.db";
    static final int    DATABASE_VERSION = 1;

    // ── tasks ──────────────────────────────────────────────────────────────
    static final String TABLE_TASKS     = "tasks";
    static final String COL_ID          = "id";
    static final String COL_TITLE       = "title";
    static final String COL_COMPLETED   = "completed";
    static final String COL_DUE_DATE    = "due_date";
    static final String COL_LIST_NAME   = "list_name";
    static final String COL_HAS_ALARM   = "has_alarm";
    static final String COL_HAS_FLAG    = "has_flag";

    // ── subtasks ───────────────────────────────────────────────────────────
    static final String TABLE_SUBTASKS       = "subtasks";
    static final String COL_SUB_ID           = "id";
    static final String COL_SUB_TASK_ID      = "task_id";
    static final String COL_SUB_TITLE        = "title";
    static final String COL_SUB_COMPLETED    = "completed";

    // ── DDL ────────────────────────────────────────────────────────────────
    private static final String SQL_CREATE_TASKS =
            "CREATE TABLE " + TABLE_TASKS + " ("
            + COL_ID        + " INTEGER PRIMARY KEY AUTOINCREMENT, "
            + COL_TITLE     + " TEXT NOT NULL, "
            + COL_COMPLETED + " INTEGER NOT NULL DEFAULT 0, "
            + COL_DUE_DATE  + " TEXT, "
            + COL_LIST_NAME + " TEXT, "
            + COL_HAS_ALARM + " INTEGER NOT NULL DEFAULT 0, "
            + COL_HAS_FLAG  + " INTEGER NOT NULL DEFAULT 0)";

    private static final String SQL_CREATE_SUBTASKS =
            "CREATE TABLE " + TABLE_SUBTASKS + " ("
            + COL_SUB_ID        + " INTEGER PRIMARY KEY AUTOINCREMENT, "
            + COL_SUB_TASK_ID   + " INTEGER NOT NULL, "
            + COL_SUB_TITLE     + " TEXT NOT NULL, "
            + COL_SUB_COMPLETED + " INTEGER NOT NULL DEFAULT 0, "
            + "FOREIGN KEY (" + COL_SUB_TASK_ID + ") REFERENCES "
            + TABLE_TASKS + "(" + COL_ID + ") ON DELETE CASCADE)";

    public TaskDbHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onConfigure(SQLiteDatabase db) {
        super.onConfigure(db);
        db.execSQL("PRAGMA foreign_keys = ON");
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        db.execSQL(SQL_CREATE_TASKS);
        db.execSQL(SQL_CREATE_SUBTASKS);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_SUBTASKS);
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_TASKS);
        onCreate(db);
    }
}

package com.example.ticktick.data;

import android.content.Context;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;


public class TaskDbHelper extends SQLiteOpenHelper {
    static final String DATABASE_NAME    = "ticktick.db";
    static final int    DATABASE_VERSION = 2;

    // ── tasks ──────────────────────────────────────────────────────────────
    static final String TABLE_TASKS     = "tasks";
    static final String COL_ID          = "id";
    static final String COL_TITLE       = "title";
    static final String COL_COMPLETED   = "completed";
    static final String COL_DUE_DATE    = "due_date";
    static final String COL_LIST_NAME   = "list_name";
    static final String COL_HAS_ALARM   = "has_alarm";
    static final String COL_HAS_FLAG    = "has_flag";
    static final String COL_DESCRIPTION  = "description";
    static final String COL_REMINDER_MINUTES = "reminder_minutes";
    static final String COL_REPEAT_TYPE = "repeat_type";

    // ── subtasks ───────────────────────────────────────────────────────────
    static final String TABLE_SUBTASKS       = "subtasks";
    static final String COL_SUB_ID           = "id";
    static final String COL_SUB_TASK_ID      = "task_id";
    static final String COL_SUB_TITLE        = "title";
    static final String COL_SUB_COMPLETED    = "completed";

    // ── DDL ────────────────────────────────────────────────────────────────
    private static final String SQL_CREATE_TASKS =
            "CREATE TABLE " + TABLE_TASKS + " ("
            + COL_ID        + " INTEGER PRIMARY KEY AUTOINCREMENT, "
            + COL_TITLE     + " TEXT NOT NULL, "
            + COL_COMPLETED + " INTEGER NOT NULL DEFAULT 0, "
            + COL_DUE_DATE  + " TEXT, "
            + COL_LIST_NAME + " TEXT, "
            + COL_HAS_ALARM + " INTEGER NOT NULL DEFAULT 0, "
            + COL_HAS_FLAG  + " INTEGER NOT NULL DEFAULT 0, "
            + COL_DESCRIPTION + " TEXT, "
            + COL_REMINDER_MINUTES + " INTEGER NOT NULL DEFAULT -1, "
            + COL_REPEAT_TYPE + " TEXT NOT NULL DEFAULT 'none')";

    private static final String SQL_CREATE_SUBTASKS =
            "CREATE TABLE " + TABLE_SUBTASKS + " ("
            + COL_SUB_ID        + " INTEGER PRIMARY KEY AUTOINCREMENT, "
            + COL_SUB_TASK_ID   + " INTEGER NOT NULL, "
            + COL_SUB_TITLE     + " TEXT NOT NULL, "
            + COL_SUB_COMPLETED + " INTEGER NOT NULL DEFAULT 0, "
            + "FOREIGN KEY (" + COL_SUB_TASK_ID + ") REFERENCES "
            + TABLE_TASKS + "(" + COL_ID + ") ON DELETE CASCADE)";

    public TaskDbHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onConfigure(SQLiteDatabase db) {
        super.onConfigure(db);
        db.execSQL("PRAGMA foreign_keys = ON");
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        db.execSQL(SQL_CREATE_TASKS);
        db.execSQL(SQL_CREATE_SUBTASKS);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        if (oldVersion < 2) {
            db.execSQL("ALTER TABLE " + TABLE_TASKS
                    + " ADD COLUMN " + COL_DESCRIPTION + " TEXT");
            db.execSQL("ALTER TABLE " + TABLE_TASKS
                    + " ADD COLUMN " + COL_REMINDER_MINUTES + " INTEGER NOT NULL DEFAULT -1");
            db.execSQL("ALTER TABLE " + TABLE_TASKS
                    + " ADD COLUMN " + COL_REPEAT_TYPE + " TEXT NOT NULL DEFAULT 'none'");
        }
    }
}

package com.example.ticktick.model;

import java.util.ArrayList;
import java.util.List;

public class Task {
    private int id;
    private String title;
    private boolean completed;
    private String dueDate;
    private String listName;
    private final List<SubTask> subTasks;
    private boolean hasAlarm;
    private boolean hasFlag;
    private String description;

    public Task(int id, String title, boolean completed, String dueDate, String listName) {
        this.id = id;
        this.title = title;
        this.completed = completed;
        this.dueDate = dueDate;
        this.listName = listName;
        this.subTasks = new ArrayList<>();
        this.hasAlarm = false;
        this.hasFlag = false;
        this.description = null;
    }

    public int getId() { return id; }
    public void setId(int id) { this.id = id; }
    public String getTitle() { return title; }
    public void setTitle(String title) { this.title = title; }
    public boolean isCompleted() { return completed; }
    public void setCompleted(boolean completed) { this.completed = completed; }
    public String getDueDate() { return dueDate; }
    public void setDueDate(String dueDate) { this.dueDate = dueDate; }
    public String getListName() { return listName; }
    public List<SubTask> getSubTasks() { return subTasks; }
    public boolean isHasAlarm() { return hasAlarm; }
    public void setHasAlarm(boolean hasAlarm) { this.hasAlarm = hasAlarm; }
    public boolean isHasFlag() { return hasFlag; }
    public void setHasFlag(boolean hasFlag) { this.hasFlag = hasFlag; }
    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }

    public static class SubTask {
        private String title;
        private boolean completed;

        public SubTask(String title) {
            this.title = title;
            this.completed = false;
        }

        public String getTitle() { return title; }
        public boolean isCompleted() { return completed; }
        public void setCompleted(boolean completed) { this.completed = completed; }
    }
}

package com.example.ticktick.model;

import java.util.ArrayList;
import java.util.List;

public class Task {
    public static final String REPEAT_NONE = "none";
    public static final String REPEAT_DAILY = "daily";
    public static final String REPEAT_WEEKLY = "weekly";
    public static final String REPEAT_MONTHLY = "monthly";

    private int id;
    private String title;
    private boolean completed;
    private String dueDate;
    private String listName;
    private final List<SubTask> subTasks;
    private boolean hasAlarm;
    private boolean hasFlag;
    private String description;
    private int reminderMinutes;
    private String repeatType;

    public Task(int id, String title, boolean completed, String dueDate, String listName) {
        this.id = id;
        this.title = title;
        this.completed = completed;
        this.dueDate = dueDate;
        this.listName = listName;
        this.subTasks = new ArrayList<>();
        this.hasAlarm = false;
        this.hasFlag = false;
        this.description = null;
        this.reminderMinutes = -1;
        this.repeatType = REPEAT_NONE;
    }

    public int getId() { return id; }
    public void setId(int id) { this.id = id; }
    public String getTitle() { return title; }
    public void setTitle(String title) { this.title = title; }
    public boolean isCompleted() { return completed; }
    public void setCompleted(boolean completed) { this.completed = completed; }
    public String getDueDate() { return dueDate; }
    public void setDueDate(String dueDate) { this.dueDate = dueDate; }
    public String getListName() { return listName; }
    public List<SubTask> getSubTasks() { return subTasks; }
    public boolean isHasAlarm() { return hasAlarm; }
    public void setHasAlarm(boolean hasAlarm) { this.hasAlarm = hasAlarm; }
    public boolean isHasFlag() { return hasFlag; }
    public void setHasFlag(boolean hasFlag) { this.hasFlag = hasFlag; }
    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }
    public int getReminderMinutes() { return reminderMinutes; }
    public void setReminderMinutes(int reminderMinutes) { this.reminderMinutes = reminderMinutes; }
    public String getRepeatType() { return repeatType; }
    public void setRepeatType(String repeatType) {
        if (repeatType == null || repeatType.isEmpty()) {
            this.repeatType = REPEAT_NONE;
            return;
        }
        this.repeatType = repeatType;
    }

    public static class SubTask {
        private String title;
        private boolean completed;

        public SubTask(String title) {
            this.title = title;
            this.completed = false;
        }

        public String getTitle() { return title; }
        public boolean isCompleted() { return completed; }
        public void setCompleted(boolean completed) { this.completed = completed; }
    }
}
